INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (693, 173202, 9, 685, '挑战书', '我们是湖滨中学98届高中部的校友，我们中大部分人当年都入选张荣金教练的湖滨中学足球队，那一年湖滨中学获得省中学生传统足球赛第2名。仅次于厦门二中。现在我们都是大一的学生，利用暑假的机会向咖啡足球队发起挑战。不知你们有没有兴趣，我们可比英中那帮没有足球细胞的家伙好玩多了。', '我们是湖滨中学98届高中部的校友，我们中大部分人当年都入选张荣金教练的湖滨中学足球队，那一年湖滨中学获得省中学生传统足球赛第2名。仅次于厦门二中。现在我们都是大一的学生，利用暑假的机会向咖啡足球队发起挑战。不知你们有没有兴趣，我们可比英中那帮没有足球细胞的家伙好玩多了。', NULL, '2002-07-23 15:01:00', 18, '20020818162717_bbsid_173202_board_9_4bf793da31.html', '20020818162717');
